import 'package:flutter/material.dart';import 'package:go_router/go_router.dart';
import '../home/home_screen.dart';import '../fixtures/fixtures_screen.dart';import '../predictions/my_predictions_screen.dart';import '../leaderboard/leaderboard_screen.dart';import '../winners/winners_screen.dart';import '../profile/profile_screen.dart';
class MainShellScreen extends StatelessWidget{final Widget child;const MainShellScreen({super.key,required this.child});static const paths=['/home','/fixtures','/my-predictions','/leaderboard','/winners','/profile'];@override Widget build(BuildContext c){final loc=GoRouterState.of(c).uri.path;final i=paths.indexWhere((p)=>loc.startsWith(p));return Scaffold(body:child,bottomNavigationBar:NavigationBar(selectedIndex:i<0?0:i,onDestinationSelected:(v)=>c.go(paths[v]),destinations:const [NavigationDestination(icon:Icon(Icons.home),label:'Home'),NavigationDestination(icon:Icon(Icons.sports_soccer),label:'Fixtures'),NavigationDestination(icon:Icon(Icons.fact_check),label:'Mine'),NavigationDestination(icon:Icon(Icons.leaderboard),label:'Leaders'),NavigationDestination(icon:Icon(Icons.emoji_events),label:'Winners'),NavigationDestination(icon:Icon(Icons.person),label:'Profile')],));}}
class HomeScreenTab extends HomeScreen{const HomeScreenTab({super.key});} class FixturesScreenTab extends FixturesScreen{const FixturesScreenTab({super.key});} class MyPredictionsScreenTab extends MyPredictionsScreen{const MyPredictionsScreenTab({super.key});} class LeaderboardScreenTab extends LeaderboardScreen{const LeaderboardScreenTab({super.key});} class WinnersScreenTab extends WinnersScreen{const WinnersScreenTab({super.key});} class ProfileScreenTab extends ProfileScreen{const ProfileScreenTab({super.key});}
